import argparse
import json
import random
import signal
import socket
import sys
import threading
import time
from typing import Dict, List, Tuple, Any

MAX_PLAYERS = 64
DEFAULT_HOST = "0.0.0.0"
DEFAULT_PORT = 27960
SERVER_NAME = "Example Game Server"
MAPS = ["arena01", "arena02", "arena03", "ctf01", "dm06"]
MODES = ["dm", "tdm", "ctf", "survival"]


class GameState:
    def __init__(self) -> None:
        self.lock = threading.Lock()
        self.start_time = time.time()
        self.round_start = time.time()
        self.server_name = SERVER_NAME
        self.map_name = random.choice(MAPS)
        self.mode = random.choice(MODES)
        self.max_players = MAX_PLAYERS
        self.players: List[Dict[str, Any]] = []
        self.next_player_id = 1
        self.tick = 0
        self.state = "warmup"
        self.scores = {"red": 0, "blue": 0}
        self._seed_players()

    def _seed_players(self) -> None:
        names = [
            "Alpha", "Bravo", "Charlie", "Delta", "Echo", "Foxtrot", "Ghost",
            "Hunter", "Iris", "Jinx", "Kilo", "Lancer", "Mako", "Nova"
        ]
        for _ in range(random.randint(4, 12)):
            self.players.append(
                {
                    "id": self.next_player_id,
                    "name": random.choice(names) + str(self.next_player_id),
                    "score": random.randint(0, 30),
                    "ping": random.randint(20, 120),
                    "team": random.choice(["red", "blue"]),
                    "connected_for": random.randint(10, 1800),
                }
            )
            self.next_player_id += 1

    def snapshot(self) -> Dict[str, Any]:
        with self.lock:
            now = time.time()
            return {
                "server": {
                    "name": self.server_name,
                    "uptime": int(now - self.start_time),
                    "tick": self.tick,
                },
                "game": {
                    "state": self.state,
                    "mode": self.mode,
                    "map": self.map_name,
                    "round_time": int(now - self.round_start),
                    "scores": dict(self.scores),
                },
                "players": [dict(p) for p in self.players],
                "player_count": len(self.players),
                "max_players": self.max_players,
            }

    def update(self) -> None:
        with self.lock:
            self.tick += 1
            if self.tick % 30 == 0:
                self.state = random.choice(["warmup", "live", "overtime", "postmatch"])
            if self.tick % 60 == 0:
                self.map_name = random.choice(MAPS)
                self.mode = random.choice(MODES)
                self.round_start = time.time()
            if self.tick % 10 == 0:
                self.scores["red"] += random.randint(0, 2)
                self.scores["blue"] += random.randint(0, 2)
            for p in self.players:
                p["score"] += random.randint(0, 2)
                p["ping"] = max(10, min(250, p["ping"] + random.randint(-5, 5)))
                p["connected_for"] += 1
            if len(self.players) < self.max_players and random.random() < 0.08:
                self.players.append(
                    {
                        "id": self.next_player_id,
                        "name": f"Player{self.next_player_id}",
                        "score": 0,
                        "ping": random.randint(20, 100),
                        "team": random.choice(["red", "blue"]),
                        "connected_for": 0,
                    }
                )
                self.next_player_id += 1
            if self.players and random.random() < 0.05:
                self.players.pop(random.randrange(len(self.players)))


class UDPGameServer:
    def __init__(self, host: str, port: int, game_state: GameState) -> None:
        self.host = host
        self.port = port
        self.game_state = game_state
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind((self.host, self.port))
        self.sock.settimeout(1.0)
        self.running = threading.Event()
        self.running.set()

    def serve_forever(self) -> None:
        while self.running.is_set():
            try:
                data, addr = self.sock.recvfrom(65535)
            except socket.timeout:
                continue
            except OSError:
                break
            threading.Thread(target=self.handle_packet, args=(data, addr), daemon=True).start()

    def handle_packet(self, data: bytes, addr: Tuple[str, int]) -> None:
        text = data.decode("utf-8", errors="ignore").strip()
        if not text:
            return

        if text.lower() in ("status", "getstatus", "query status", "serverinfo"):
            payload = self.game_state.snapshot()
            response = {
                "type": "status",
                "ok": True,
                "data": payload,
            }
            raw = json.dumps(response, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
            self.sock.sendto(raw, addr)
            return

        if text.lower() == "ping":
            self.sock.sendto(b'{"type":"pong","ok":true}', addr)
            return

        self.sock.sendto(b'{"type":"error","ok":false,"error":"unknown_query"}', addr)

    def shutdown(self) -> None:
        self.running.clear()
        try:
            self.sock.close()
        except OSError:
            pass


def simulation_loop(state: GameState, running: threading.Event) -> None:
    while running.is_set():
        state.update()
        time.sleep(1.0)


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--host", default=DEFAULT_HOST)
    parser.add_argument("--port", type=int, default=DEFAULT_PORT)
    args = parser.parse_args()

    state = GameState()
    server = UDPGameServer(args.host, args.port, state)
    sim_running = threading.Event()
    sim_running.set()

    sim_thread = threading.Thread(target=simulation_loop, args=(state, sim_running), daemon=True)
    sim_thread.start()

    def stop_handler(signum=None, frame=None) -> None:
        sim_running.clear()
        server.shutdown()

    signal.signal(signal.SIGINT, stop_handler)
    signal.signal(signal.SIGTERM, stop_handler)

    try:
        print(f"UDP game server listening on {args.host}:{args.port}", flush=True)
        server.serve_forever()
    finally:
        sim_running.clear()
        server.shutdown()

    return 0


if __name__ == "__main__":
    sys.exit(main())